class Solution:
    def isOneBitCharacter(self, bits: List[int]) -> bool:
        i, n = 0, len(bits)
        while i < n:
            if bits[i] == 0:
                i += 1
            elif i + 1 < n:
                i += 2
            else:
                return False
        return True

