class Solution {
public:
    bool isOneBitCharacter(vector<int>& bits) {
        int i = 0, n = bits.size();
        while (i < n) {
            if (bits[i] == 0) i++;
            else if (i + 1 < n) i += 2;
            else return false;
        }
        return true;
    }
};

